mapper.select:
SELECT * FROM SYNC_TASK_LOG


        AND STATUS = #{status}


        AND TASK_ID = #{taskId}


        AND TASK_NAME LIKE '%' || LOWER(#{keyword}) || '%'


        AND START_TIME >= #{startTimeAfter}


        AND END_TIME >= #{endTimeAfter}


        AND END_TIME <= #{endTimeBefore}


        AND START_TIME >= #{startTimeFrom}


        AND START_TIME < #{startTimeTo}


        AND TRUNC(START_TIME) = TRUNC(SYSDATE)


ORDER BY START_TIME DESC

SELECT * FROM SYNC_TASK_LOG


        AND STATUS = #{status}


        AND (LOWER(TASK_ID) LIKE CONCAT('%', LOWER(#{keyword}), '%')
             OR LOWER(TASK_NAME) LIKE CONCAT('%', LOWER(#{keyword}), '%'))


        AND START_TIME >= #{startTimeAfter}


        AND END_TIME >= #{endTimeAfter}


        AND END_TIME <= #{endTimeBefore}


        AND START_TIME >= #{startTimeFrom}


        AND START_TIME < #{startTimeTo}


        AND DATE(START_TIME) = CURDATE()


ORDER BY START_TIME DESC

mapper.update:
UPDATE SYNC_TASK_LOG SET STATUS=#{status}, TOTAL_COUNT=#{totalCount},
SUCCESS_COUNT=#{successCount}, FAIL_COUNT=#{failCount},
INSERT_COUNT=#{insertCount}, UPDATE_COUNT=#{updateCount}, SKIP_COUNT=#{skipCount},
ERROR_MSG=#{errorMsg,jdbcType=CLOB}, END_TIME=#{endTime}
WHERE ID=#{id}

mapper.select:
SELECT TASK_ID, COUNT(*) AS SYNC_COUNT, SUM(CASE WHEN STATUS = 2 THEN 1 ELSE 0 END) AS SUCCESS_COUNT, SUM(CASE WHEN STATUS = 3 THEN 1 ELSE 0 END) AS FAIL_COUNT, MAX(START_TIME) AS LAST_SYNC_TIME FROM SYNC_TASK_LOG WHERE TASK_ID IN
#{taskId}
GROUP BY TASK_ID
